import{_ as t,o,c as i,a2 as s}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"Notifications et webhooks","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/notifications.md","filePath":"fr/guide/notifications.md"}'),a={name:"fr/guide/notifications.md"};function n(r,e,d,l,c,u){return o(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="notifications-et-webhooks" tabindex="-1">Notifications et webhooks <a class="header-anchor" href="#notifications-et-webhooks" aria-label="Permalink to &quot;Notifications et webhooks&quot;">​</a></h1><p>Nid vous informe des événements importants via des notifications in-app et des webhooks vers vos services préférés.</p><hr><h2 id="notifications-in-app" tabindex="-1">Notifications in-app <a class="header-anchor" href="#notifications-in-app" aria-label="Permalink to &quot;Notifications in-app&quot;">​</a></h2><h3 id="cloche-de-notifications" tabindex="-1">Cloche de notifications <a class="header-anchor" href="#cloche-de-notifications" aria-label="Permalink to &quot;Cloche de notifications&quot;">​</a></h3><p>L&#39;icône <strong>🔔</strong> dans la barre de navigation affiche vos notifications. Le badge rouge indique le nombre de notifications non lues.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : cloche de notifications avec badge et panneau déroulant montrant les notifications</em></p></blockquote><h3 id="actions-sur-les-notifications" tabindex="-1">Actions sur les notifications <a class="header-anchor" href="#actions-sur-les-notifications" aria-label="Permalink to &quot;Actions sur les notifications&quot;">​</a></h3><ul><li>Cliquez sur une notification pour la marquer comme lue</li><li><strong>Tout marquer comme lu</strong> : marque toutes les notifications comme lues</li><li><strong>Supprimer</strong> : supprime une notification individuellement</li><li><strong>Supprimer les lues</strong> : supprime toutes les notifications déjà lues</li></ul><h3 id="types-de-notifications" tabindex="-1">Types de notifications <a class="header-anchor" href="#types-de-notifications" aria-label="Permalink to &quot;Types de notifications&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Notification</th><th>Description</th></tr></thead><tbody><tr><td><strong>Rapport hebdomadaire</strong></td><td>Résumé de votre activité email de la semaine</td></tr><tr><td><strong>Job terminé</strong></td><td>Un job (archivage, suppression, etc.) s&#39;est terminé avec succès</td></tr><tr><td><strong>Job en échec</strong></td><td>Un job a échoué après 3 tentatives</td></tr><tr><td><strong>Règle exécutée</strong></td><td>Une règle automatique a été exécutée</td></tr><tr><td><strong>Alerte quota</strong></td><td>Votre quota de stockage approche de la limite</td></tr><tr><td><strong>Alerte intégrité</strong></td><td>La vérification d&#39;intégrité des archives a détecté un problème</td></tr></tbody></table><hr><h2 id="preferences-de-notifications" tabindex="-1">Préférences de notifications <a class="header-anchor" href="#preferences-de-notifications" aria-label="Permalink to &quot;Préférences de notifications&quot;">​</a></h2><p>Personnalisez les canaux de notification pour chaque type d&#39;événement.</p><ol><li>Rendez-vous dans <strong>Paramètres</strong> → section <strong>Préférences de notifications</strong></li><li>Pour chaque type de notification, activez ou désactivez les canaux :</li></ol><table tabindex="0"><thead><tr><th>Canal</th><th>Description</th></tr></thead><tbody><tr><td>🔔 <strong>In-app</strong></td><td>Crée une notification dans la cloche du header</td></tr><tr><td>💬 <strong>Toast</strong></td><td>Affiche une pop-up temporaire en bas de page</td></tr></tbody></table><blockquote><p>📸 <em>Capture d&#39;écran suggérée : tableau des préférences de notifications avec les toggles in-app et toast pour chaque type</em></p></blockquote><p>Chaque toggle prend effet <strong>immédiatement</strong> — pas besoin de sauvegarder.</p><hr><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Les webhooks permettent d&#39;envoyer des notifications vers des services externes quand un événement se produit dans Nid.</p><h3 id="types-supportes" tabindex="-1">Types supportés <a class="header-anchor" href="#types-supportes" aria-label="Permalink to &quot;Types supportés&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Discord</strong></td><td>Message dans un salon Discord via webhook URL</td></tr><tr><td><strong>Slack</strong></td><td>Message dans un channel Slack via Incoming Webhook</td></tr><tr><td><strong>Ntfy</strong></td><td>Notification push via <a href="https://ntfy.sh" target="_blank" rel="noreferrer">ntfy.sh</a></td></tr><tr><td><strong>Générique</strong></td><td>Requête HTTP POST vers n&#39;importe quelle URL</td></tr></tbody></table><h3 id="evenements-disponibles" tabindex="-1">Événements disponibles <a class="header-anchor" href="#evenements-disponibles" aria-label="Permalink to &quot;Événements disponibles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Événement</th><th>Description</th></tr></thead><tbody><tr><td><code>job.completed</code></td><td>Un job s&#39;est terminé avec succès</td></tr><tr><td><code>job.failed</code></td><td>Un job a échoué</td></tr><tr><td><code>rule.executed</code></td><td>Une règle automatique a été exécutée</td></tr><tr><td><code>quota.warning</code></td><td>Le quota de stockage est presque atteint</td></tr><tr><td><code>integrity.failed</code></td><td>La vérification d&#39;intégrité a détecté un problème</td></tr></tbody></table><h3 id="configurer-un-webhook" tabindex="-1">Configurer un webhook <a class="header-anchor" href="#configurer-un-webhook" aria-label="Permalink to &quot;Configurer un webhook&quot;">​</a></h3><ol><li>Dans <strong>Paramètres</strong> → section <strong>Webhooks</strong></li><li>Cliquez sur <strong>Ajouter un webhook</strong></li><li>Renseignez : <ul><li><strong>Nom</strong> : un identifiant libre (ex. : &quot;Notif Discord&quot;)</li><li><strong>URL</strong> : l&#39;URL du webhook de votre service</li><li><strong>Type</strong> : Discord, Slack, Ntfy ou Générique</li><li><strong>Événements</strong> : cochez les événements qui déclenchent le webhook</li><li><strong>Utilisateur / Mot de passe</strong> <em>(Ntfy uniquement)</em> : identifiants si le topic est protégé par authentification</li></ul></li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : formulaire de création d&#39;un webhook avec les champs nom, URL, type et événements</em></p></blockquote><h3 id="tester-un-webhook" tabindex="-1">Tester un webhook <a class="header-anchor" href="#tester-un-webhook" aria-label="Permalink to &quot;Tester un webhook&quot;">​</a></h3><p>Cliquez sur <strong>Tester</strong> à côté d&#39;un webhook pour envoyer un message test et vérifier que la connexion fonctionne.</p><h3 id="activer-desactiver" tabindex="-1">Activer / désactiver <a class="header-anchor" href="#activer-desactiver" aria-label="Permalink to &quot;Activer / désactiver&quot;">​</a></h3><p>Le toggle à côté de chaque webhook permet de l&#39;activer ou le désactiver sans le supprimer.</p><h3 id="securite-webhooks-generiques" tabindex="-1">Sécurité (webhooks génériques) <a class="header-anchor" href="#securite-webhooks-generiques" aria-label="Permalink to &quot;Sécurité (webhooks génériques)&quot;">​</a></h3><p>Les webhooks de type <strong>Générique</strong> incluent automatiquement un header <code>X-Webhook-Signature</code> contenant un HMAC-SHA256 du payload. Votre serveur peut vérifier cette signature pour s&#39;assurer que la requête provient bien de Nid.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : liste des webhooks configurés avec les colonnes nom, type, événements, toggle actif/inactif et bouton tester</em></p></blockquote><hr><h2 id="exemples-d-utilisation" tabindex="-1">Exemples d&#39;utilisation <a class="header-anchor" href="#exemples-d-utilisation" aria-label="Permalink to &quot;Exemples d&#39;utilisation&quot;">​</a></h2><h3 id="discord" tabindex="-1">Discord <a class="header-anchor" href="#discord" aria-label="Permalink to &quot;Discord&quot;">​</a></h3><ol><li>Dans Discord, créez un webhook dans un salon : <strong>Paramètres du salon</strong> → <strong>Intégrations</strong> → <strong>Webhooks</strong> → <strong>Nouveau webhook</strong></li><li>Copiez l&#39;URL du webhook</li><li>Dans Nid, créez un webhook de type <strong>Discord</strong> avec cette URL</li><li>Sélectionnez les événements à notifier</li></ol><h3 id="ntfy" tabindex="-1">Ntfy <a class="header-anchor" href="#ntfy" aria-label="Permalink to &quot;Ntfy&quot;">​</a></h3><p><a href="https://ntfy.sh" target="_blank" rel="noreferrer">ntfy</a> permet de recevoir des notifications push sur votre téléphone ou navigateur.</p><h4 id="topic-public-sans-authentification" tabindex="-1">Topic public (sans authentification) <a class="header-anchor" href="#topic-public-sans-authentification" aria-label="Permalink to &quot;Topic public (sans authentification)&quot;">​</a></h4><ol><li>Choisissez un topic sur <a href="https://ntfy.sh" target="_blank" rel="noreferrer">ntfy.sh</a> (ex. : <code>nid-alerts</code>)</li><li>Dans Nid, créez un webhook de type <strong>Ntfy</strong> avec l&#39;URL <code>https://ntfy.sh/nid-alerts</code></li><li>Installez l&#39;app ntfy sur votre téléphone et abonnez-vous au même topic</li></ol><h4 id="topic-protege-avec-login-mot-de-passe" tabindex="-1">Topic protégé (avec login / mot de passe) <a class="header-anchor" href="#topic-protege-avec-login-mot-de-passe" aria-label="Permalink to &quot;Topic protégé (avec login / mot de passe)&quot;">​</a></h4><p>Si vous hébergez votre propre serveur ntfy ou utilisez un topic protégé par mot de passe :</p><ol><li>Dans Nid, créez un webhook de type <strong>Ntfy</strong> avec l&#39;URL de votre serveur (ex. : <code>https://ntfy.example.com/mon-topic</code>)</li><li>Renseignez le <strong>nom d&#39;utilisateur</strong> et le <strong>mot de passe</strong> dans les champs qui apparaissent quand le type Ntfy est sélectionné</li><li>Les identifiants sont envoyés via l&#39;en-tête HTTP <code>Authorization: Basic</code> (encodage Base64)</li><li>Cliquez sur <strong>Tester</strong> pour vérifier que l&#39;authentification fonctionne</li></ol><div class="tip custom-block"><p class="custom-block-title">Serveur ntfy auto-hébergé</p><p>Si vous utilisez un serveur ntfy auto-hébergé avec contrôle d&#39;accès (<code>auth-default-access: deny-all</code>), vous devez créer un utilisateur et lui autoriser l&#39;accès en écriture au topic :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ntfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> monuser</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ntfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> monuser</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mon-topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write</span></span></code></pre></div></div><div class="warning custom-block"><p class="custom-block-title">Sécurité</p><p>Les identifiants ntfy sont stockés en clair dans la base de données. Utilisez un compte dédié avec des permissions minimales (écriture seule sur le topic concerné).</p></div>`,48)])])}const g=t(a,[["render",n]]);export{p as __pageData,g as default};
